from colorama import Fore, Style, init
init(autoreset=True)

class Board:
    def __init__(self):
        self.board = [
            [None] * 8 for _ in range(8)
        ]
        self.setup_board()

    def setup_board(self):
        # Place pieces on the board
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("red", (row, col))

        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece("black", (row, col))

    def print_board(self):
        for row in self.board:
            for piece in row:
                if piece is None:
                    print(". ", end="")
                else:
                    print(piece.color + piece.symbol() + Style.RESET_ALL, end=" ")
            print()

    def move_piece(self, start, end):
        piece = self.board[start[0]][start[1]]
        if piece is not None and self.is_valid_move(start, end):
            self.board[end[0]][end[1]] = piece
            self.board[start[0]][start[1]] = None

            # Check for capturing
            if abs(start[0] - end[0]) == 2:
                capture_row = (start[0] + end[0]) // 2
                capture_col = (start[1] + end[1]) // 2
                self.board[capture_row][capture_col] = None

            # Check for kinging
            if piece.color == "red" and end[0] == 7:
                piece.make_king()
            elif piece.color == "black" and end[0] == 0:
                piece.make_king()

    def is_valid_move(self, start, end):
        row_diff = abs(start[0] - end[0])
        col_diff = abs(start[1] - end[1])

        # Simple move
        if row_diff == 1 and col_diff == 1:
            return self.board[end[0]][end[1]] is None

        # Jump (capturing)
        if row_diff == 2 and col_diff == 2:
            capture_row = (start[0] + end[0]) // 2
            capture_col = (start[1] + end[1]) // 2
            piece_to_capture = self.board[capture_row][capture_col]
            return piece_to_capture is not None and piece_to_capture.color != self.board[start[0]][start[1]].color

        return False

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position

    def make_king(self):
        self.symbol = "K"

    def symbol(self):
        if self.color == "red":
            return "R" + (self.symbol if hasattr(self, 'symbol') else "")
        else:
            return "B" + (self.symbol if hasattr(self, 'symbol') else "")
