# src/board.py

import numpy as np
from typing import Tuple, List, Optional

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with checkers pieces
        for i in range(3):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = -1  # Black pieces
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 1   # White pieces

    def display_board(self):
        # Display the board with piece characters
        symbols = {0: '.', -1: 'b', 1: 'w'}
        print("  A B C D E F G H")
        for i, row in enumerate(self.board):
            print(f"{8-i} " + ''.join(symbols[piece] for piece in row))

    def is_valid_move(self, from_pos: Tuple[int, int], to_pos: Tuple[int, int]) -> bool:
        # Check if the move is valid
        x1, y1 = from_pos
        x2, y2 = to_pos
        piece = self.board[x1][y1]
        if piece == 0 or (abs(x1 - x2) != 2 and abs(y1 - y2) != 2):
            return False
        if piece > 0 and x2 < x1:
            return False
        if piece < 0 and x2 > x1:
            return False
        intermediate = ((x1 + x2) // 2, (y1 + y2) // 2)
        if self.board[intermediate] == 0 or np.sign(self.board[intermediate]) == np.sign(piece):
            return False
        return True

    def execute_move(self, from_pos: Tuple[int, int], to_pos: Tuple[int, int]):
        # Execute a move and capture pieces
        x1, y1 = from_pos
        x2, y2 = to_pos
        self.board[x2][y2] = self.board[x1][y1]
        intermediate = ((x1 + x2) // 2, (y1 + y2) // 2)
        self.board[intermediate] = 0

    def check_winner(self) -> Optional[int]:
        # Check for a winner
        if np.any(self.board == -1):
            return -1  # Black wins
        elif np.any(self.board == 1):
            return 1   # White wins
        else:
            return None  # Draw
```

